// apps/mobile/src/primereact/datatable/DataTable.tsx

import React, {
  forwardRef,
  useCallback,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { FlatList, Pressable, Text, View } from "react-native";
import type {
  DataTableProps,
  DataTableRef,
  DataTableRowData,
  DataTableSortMeta,
  SortOrder,
  ColumnProps,
  DataTableFilterMeta,
  DataKey,
} from "./Datatable.types";
import { Column } from "./Column";

function isColumnElement(node: any): node is React.ReactElement<ColumnProps<any>> {
  return !!node && node.type === Column;
}

function getRowKey<TValue>(
  dataKey: DataKey<TValue> | undefined,
  row: any,
  rowIndex: number,
) {
  if (!dataKey) return String(rowIndex);
  if (typeof dataKey === "function") {
    const v = dataKey(row);
    return v == null ? String(rowIndex) : String(v);
  }
  const v = row?.[dataKey];
  return v == null ? String(rowIndex) : String(v);
}

function deepEquals(a: any, b: any) {
  // Simple deep compare (enough for selection). Replace later if needed.
  try {
    return JSON.stringify(a) === JSON.stringify(b);
  } catch {
    return a === b;
  }
}

const DataTable = forwardRef(function DataTableInner<TValue = any>(
  props: DataTableProps<TValue>,
  ref: React.Ref<DataTableRef<TValue>>,
) {
  const {
    value,
    children,
    style,
    tableStyle,
    showHeaders = true,
    emptyMessage = "No results found",
    loading = false,

    // paging
    paginator = false,
    alwaysShowPaginator = true,
    rows: rowsProp,
    first: firstProp,

    // sorting
    sortMode = "single",
    sortField: sortFieldProp,
    sortOrder: sortOrderProp,
    multiSortMeta: multiSortMetaProp,

    // selection
    selectionMode,
    compareSelectionBy = "deepEquals",
    metaKeySelection = true, // web behavior; RN ignores metaKey but keeps prop.
    selectionPageOnly = false,
    onSelectionChange,
    onRowSelect,
    onRowUnselect,
    onSelectAllChange,
    showSelectAll,

    // callbacks
    onRowClick,
    onSort,
    onPage,
    onValueChange,

    // filters (present; minimal internal storage now)
    filters: filtersProp,

    totalRecords,
    dataKey,

    testID,
  } = props;

  /** 1) Extract columns from children (PrimeReact-style) */
  const columns: ColumnProps<TValue>[] = useMemo(() => {
    const cols: ColumnProps<TValue>[] = [];
    React.Children.forEach(children, (child) => {
      if (isColumnElement(child)) cols.push(child.props as ColumnProps<TValue>);
    });
    return cols.filter((c) => !c.hidden);
  }, [children]);

  /** 2) Internal state (uncontrolled fallback like PrimeReact) */
  const [firstState, setFirstState] = useState<number>(firstProp ?? 0);
  const [rowsState, setRowsState] = useState<number>(rowsProp ?? 10);

  const [sortFieldState, setSortFieldState] = useState<string | undefined>(
    sortFieldProp,
  );
  const [sortOrderState, setSortOrderState] = useState<SortOrder>(
    sortOrderProp ?? null,
  );
  const [multiSortMetaState, setMultiSortMetaState] = useState<
    DataTableSortMeta[] | null | undefined
  >(multiSortMetaProp ?? null);

  const [filtersState, setFiltersState] = useState<DataTableFilterMeta | undefined>(
    filtersProp ?? undefined,
  );
  const isRowsControlled = props.rows !== undefined;

  // Keep latest props mirrored (without forcing controlled mode yet)
  const first = firstProp ?? firstState;
  const rows = isRowsControlled ? rowsProp : rowsState;

  const sortField = sortFieldProp ?? sortFieldState;
  const sortOrder = sortOrderProp ?? sortOrderState;
  const multiSortMeta = multiSortMetaProp ?? multiSortMetaState;

  const filters = filtersProp ?? filtersState;

  /** 3) Selection (we keep it very compatible, but minimal behavior now) */
  const selectionRef = useRef<any>(undefined); // internal snapshot for uncontrolled usage
  const compareFn = useMemo(()=>compareSelectionBy === "equals" ? (a: any, b: any) => a === b : deepEquals,[compareSelectionBy]);

  const isSelected = useCallback(
    (row: any) => {
      const sel = selectionRef.current;
      if (selectionMode === "multiple" || selectionMode === "checkbox") {
        if (!Array.isArray(sel)) return false;
        return sel.some((x: any) => compareFn(x, row));
      }
      if (selectionMode === "single" || selectionMode === "radiobutton") {
        if (sel == null) return false;
        return compareFn(sel, row);
      }
      return false;
    },
    [selectionMode, compareFn],
  );



  const updateRows = useCallback((next: number) => {
    if (!isRowsControlled) {
      setRowsState(next);
    }
  },[isRowsControlled]);

  const updateSelection = useCallback(
    (row: any, rowIndex: number) => {
      // In PrimeReact, metaKeySelection affects toggling. On RN we treat press as toggle.
      const originalEvent = undefined;

      if (selectionMode === "multiple" || selectionMode === "checkbox") {
        const prev: any[] = Array.isArray(selectionRef.current) ? selectionRef.current : [];
        const exists = prev.some((x) => compareFn(x, row));
        const next = exists ? prev.filter((x) => !compareFn(x, row)) : [...prev, row];
        selectionRef.current = next;

        onSelectionChange?.({
          originalEvent,
          value: next as any,
          type: exists ? "multiple" : "multiple",
        });

        if (!exists) onRowSelect?.({ originalEvent, data: row, type: "row" });
        else onRowUnselect?.({ originalEvent, data: row, type: "row" });

        return;
      }

      if (selectionMode === "single" || selectionMode === "radiobutton") {
        const prev = selectionRef.current;
        const exists = prev != null && compareFn(prev, row);
        const next = exists ? null : row;
        selectionRef.current = next;

        onSelectionChange?.({
          originalEvent,
          value: next as any,
          type: selectionMode === "radiobutton" ? "radio" : "single",
        });

        if (!exists && next != null) onRowSelect?.({ originalEvent, data: row, type: "row" });
        if (exists) onRowUnselect?.({ originalEvent, data: row, type: "row" });

        return;
      }
    },
    [selectionMode, compareFn, onSelectionChange, onRowSelect, onRowUnselect],
  );

 /* const selectAllOnPage = useCallback(
    (checked: boolean) => {
      const originalEvent = undefined;
      const page = processedDataPage; // current page slice
      if (!Array.isArray(page)) return;

      if (checked) {
        selectionRef.current = page;
        onSelectionChange?.({ originalEvent, value: page as any, type: "all" });
        onSelectAllChange?.({ originalEvent, checked: true });
        props.onAllRowsSelect?.({ originalEvent, data: page, type: "all" });
      } else {
        selectionRef.current = [];
        onSelectionChange?.({ originalEvent, value: [] as any, type: "all" });
        onSelectAllChange?.({ originalEvent, checked: false });
        props.onAllRowsUnselect?.({ originalEvent, data: [], type: "all" });
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [onSelectionChange, onSelectAllChange],
  );*/

  /** 4) Process data: sort (filters later), then slice (pagination) */
  const rawArray = useMemo(()=>(value ?? []) as any[],[value]);
  const effectiveTotalRecords = totalRecords ?? rawArray.length;

  const sortedData = useMemo(() => {
    const data = [...rawArray];

    const sortByField = (field: string, order: SortOrder) => {
      if (!field || order === undefined || order === 0) return;
      data.sort((a, b) => {
        const av = a?.[field];
        const bv = b?.[field];
        if (av == null && bv == null) return 0;
        if (av == null) return -1 * (order as number);
        if (bv == null) return 1 * (order as number);
        if (av < bv) return -1 * (order as number);
        if (av > bv) return 1 * (order as number);
        return 0;
      });
    };

    if (sortMode === "single") {
      if (sortField) sortByField(sortField, sortOrder);
      return data;
    }

    // multiple
    const meta = multiSortMeta ?? [];
    if (!meta || meta.length === 0) return data;

    data.sort((a, b) => {
      for (const m of meta) {
        const field = m.field;
        const order = m.order ?? 0;
        const av = a?.[field];
        const bv = b?.[field];

        if (av == null && bv == null) continue;
        if (av == null) return -1 * (order as number);
        if (bv == null) return 1 * (order as number);
        if (av < bv) return -1 * (order as number);
        if (av > bv) return 1 * (order as number);
      }
      return 0;
    });

    return data;
  }, [rawArray, sortMode, sortField, sortOrder, multiSortMeta]);

  const processedData = useMemo(() => {
    // Filters not implemented yet (but meta is stored; we will implement match modes next)
    return sortedData;
  }, [sortedData]);

  const pageCount = useMemo(() => {
    if (!paginator) return 1;
    const r = rows || 1;
    return Math.max(1, Math.ceil(effectiveTotalRecords / r));
  }, [paginator, rows, effectiveTotalRecords]);

  const processedDataPage = useMemo(() => {
    if (!paginator) return processedData;
    const start = Math.max(0, first);
    const end = Math.max(0, start + (rows ?? 0));
    return processedData.slice(start, end);
  }, [processedData, paginator, first, rows]);

  /** 5) Sorting interactions from header press */
  const toggleSort = useCallback(
    (col: ColumnProps<TValue>) => {
      if (!col.sortable) return;
      const field = col.sortField ?? col.field;
      if (!field) return;

      // const originalEvent = undefined;

      if (sortMode === "single") {
        const isSame = sortField === field;
        const nextOrder: SortOrder =
          !isSame ? 1 : sortOrder === 1 ? -1 : sortOrder === -1 ? 0 : 1;

        setSortFieldState(field);
        setSortOrderState(nextOrder);

        onSort?.({
          first,
          rows: rows ?? 0,
          page: rows ? Math.floor(first / rows) : 0,
          pageCount,
          sortField: field,
          sortOrder: nextOrder,
          multiSortMeta: null,
          filters: filters ?? ({} as any),
        });

        return;
      }

      // multiple sort: add/update/remove
      const prev = (multiSortMeta ?? []) || [];
      const idx = prev.findIndex((m) => m.field === field);
      let next: DataTableSortMeta[] = [];

      if (idx === -1) {
        next = [...prev, { field, order: 1 }];
      } else {
        const cur = prev[idx];
        const nextOrder: SortOrder = cur?.order === 1 ? -1 : cur?.order === -1 ? 0 : 1;
        if (nextOrder === undefined || nextOrder === 0) {
          next = prev.filter((m) => m.field !== field);
        } else {
          next = prev.map((m) => (m.field === field ? { ...m, order: nextOrder } : m));
        }
      }

      setMultiSortMetaState(next);

      onSort?.({
        first,
        rows: rows ?? 0,
        page: rows ? Math.floor(first / rows) : 0,
        pageCount,
        sortField: field,
        sortOrder: null,
        multiSortMeta: next,
        filters: filters ?? ({} as any),
      });
    },
    [filters, first, multiSortMeta, onSort, pageCount, rows, sortField, sortMode, sortOrder],
  );

  /** 6) Paging interactions (minimal) */
  const goToPage = useCallback(
    (page: number) => {
      const p = Math.max(0, Math.min(page, pageCount - 1));
      const nextFirst = p * (rows ?? 0);

      setFirstState(nextFirst);
      rows && updateRows(rows);

      onPage?.({
        first: nextFirst,
        rows: rows ?? 0,
        page: p,
        pageCount,
        sortField: sortField ?? "",
        sortOrder,
        multiSortMeta: multiSortMeta ?? null,
        filters: filters ?? ({} as any),
      });
    },
    [filters, multiSortMeta, onPage, pageCount, rows, sortField, sortOrder, updateRows],
  );

  /** 7) Expose PrimeReact ref methods */
  useImperativeHandle(
    ref,
    (): DataTableRef<TValue> => ({
      clearState: () => {
        // stateStorage not implemented yet
      },
      closeEditingCell: () => {
        // editMode not implemented yet
      },
      closeEditingRows: () => {
        // editMode not implemented yet
      },
      exportCSV: (_options?: any) => {
        // RN: stub now, will implement using share/save later
      },
      filter: (v, field, mode) => {
        // store filters and emit onFilter (PrimeReact style)
        const next: DataTableFilterMeta = { ...(filters ?? {}) };
        next[field] = { value: v, matchMode: mode };
        setFiltersState(next);

        props.onFilter?.({
          first,
          rows: rows ?? 0,
          page: rows ? Math.floor(first / rows) : 0,
          pageCount,
          sortField: sortField ?? "",
          sortOrder,
          multiSortMeta: multiSortMeta ?? null,
          filters: next,
        });
      },
      getElement: () => null,
      getFilterMeta: () => filters,
      getProcessedData: () => processedData as any,
      getSortMeta: () => (multiSortMeta ?? undefined) as any,
      getTable: () => null,
      getVirtualScroller: () => null,
      reset: () => {
        setFirstState(0);
        setSortFieldState(undefined);
        setSortOrderState(null);
        setMultiSortMetaState(null);
        setFiltersState(undefined);
      },
      resetColumnOrder: () => {},
      resetResizeColumnsWidth: () => {},
      resetScroll: () => {},
      restoreColumnWidths: () => {},
      restoreState: () => {},
      restoreTableState: (_state: any) => {},
      saveState: () => {},
      setFilterMeta: (f: DataTableFilterMeta) => setFiltersState(f),
      setSortMeta: (s: DataTableSortMeta[]) => setMultiSortMetaState(s),
    }),
    [
      filters,
      first,
      multiSortMeta,
      pageCount,
      processedData,
      props,
      rows,
      sortField,
      sortOrder,
    ],
  );

  /** 8) Tell consumer what value is being rendered (PrimeReact onValueChange) */
  const lastValueRef = useRef<any>(null);
  useMemo(() => {
    if (!onValueChange) return;
    if (lastValueRef.current !== processedDataPage) {
      lastValueRef.current = processedDataPage;
      onValueChange(processedDataPage as any);
    }
  }, [onValueChange, processedDataPage]);

  /** 9) Render helpers */
  const renderHeaderCell = (col: ColumnProps<TValue>, index: number) => {
    const headerNode =
      typeof col.header === "function" ? col.header({ props: col }) : col.header;

    const label =
      headerNode == null ? String(col.field ?? "") : (headerNode as any);

    const isSortable = !!col.sortable && (col.field || col.sortField);

    return (
      <Pressable
        key={`h-${index}-${col.field ?? col.sortField ?? index}`}
        onPress={() => toggleSort(col)}
        disabled={!isSortable}
        style={[
          { paddingVertical: 10, paddingHorizontal: 8, flex: 1 },
          col.headerStyle as any,
        ]}
      >
        {React.isValidElement(label) ? (
          label
        ) : (
          <Text style={[{ fontWeight: "600" }, col.headerTextStyle as any]}>
            {String(label)}
          </Text>
        )}
      </Pressable>
    );
  };

  const renderRow = ({ item, index }: { item: DataTableRowData<TValue>; index: number }) => {
    const selected = isSelected(item);

    return (
      <Pressable
        onPress={() => {
          onRowClick?.({ data: item as any, originalEvent: undefined, index });
          if (selectionMode) updateSelection(item, index);
        }}
        style={[
          {
            flexDirection: "row",
            alignItems: "stretch",
            opacity: loading ? 0.6 : 1,
          },
          selected ? { backgroundColor: "rgba(0,0,0,0.06)" } : null,
        ]}
      >
        {columns.map((col, cIndex) => {
          const content =
            typeof col.body === "function"
              ? col.body(item as any, { rowIndex: index, field: col.field })
              : col.body;

          const fallback = col.field ? item?.[col.field] : undefined;

          return (
            <View
              key={`c-${index}-${cIndex}-${col.field ?? cIndex}`}
              style={[
                { paddingVertical: 10, paddingHorizontal: 8, flex: 1 },
                col.bodyStyle as any,
              ]}
            >
              {content != null ? (
                React.isValidElement(content) ? (
                  content
                ) : (
                  <Text style={col.bodyTextStyle as any}>{String(content)}</Text>
                )
              ) : (
                <Text style={col.bodyTextStyle as any}>
                  {fallback == null ? "" : String(fallback)}
                </Text>
              )}
            </View>
          );
        })}
      </Pressable>
    );
  };

  const renderEmpty = () => {
    const msg = typeof emptyMessage === "function" ? emptyMessage(props) : emptyMessage;
    return (
      <View style={{ paddingVertical: 16, paddingHorizontal: 12 }}>
        {React.isValidElement(msg) ? (
          msg
        ) : (
          <Text style={{ opacity: 0.7 }}>{String(msg)}</Text>
        )}
      </View>
    );
  };

  const renderPaginator = () => {
    if (!paginator) return null;
    if (!alwaysShowPaginator && pageCount <= 1) return null;

    const page = rows ? Math.floor(first / rows) : 0;

    return (
      <View style={{ flexDirection: "row", justifyContent: "space-between", padding: 10 }}>
        <Pressable onPress={() => goToPage(page - 1)} disabled={page <= 0}>
          <Text style={{ opacity: page <= 0 ? 0.4 : 1 }}>Prev</Text>
        </Pressable>

        <Text>
          {page + 1} / {pageCount}
        </Text>

        <Pressable onPress={() => goToPage(page + 1)} disabled={page >= pageCount - 1}>
          <Text style={{ opacity: page >= pageCount - 1 ? 0.4 : 1 }}>Next</Text>
        </Pressable>
      </View>
    );
  };

  // Header/footer slots (PrimeReact supports node or function)
  const headerNode = typeof props.header === "function" ? props.header(props) : props.header;
  const footerNode = typeof props.footer === "function" ? props.footer(props) : props.footer;

  return (
    <View testID={testID} style={[{ width: "100%" }, style as any]}>
      {headerNode ? <View style={{ padding: 8 }}>{headerNode as any}</View> : null}

      {showHeaders ? (
        <View style={[{ flexDirection: "row" }, tableStyle as any]}>
          {columns.map(renderHeaderCell)}
        </View>
      ) : null}

      {loading ? (
        <View style={{ padding: 12 }}>
          <Text>Loading...</Text>
        </View>
      ) : null}

      {processedDataPage.length === 0 ? (
        renderEmpty()
      ) : (
        <FlatList
          data={processedDataPage as any[]}
          keyExtractor={(row, i) => getRowKey(dataKey, row, i)}
          renderItem={renderRow as any}
        />
      )}

      {renderPaginator()}

      {footerNode ? <View style={{ padding: 8 }}>{footerNode as any}</View> : null}
    </View>
  );
});

export default DataTable;
